        "command": "cd RELEASE_WORKSPACE && python - <<'PY'\nimport asyncio, os, httpx, re\nfrom pathlib import Path\nfrom playwright.async_api import async_playwright\n\nWORKSPACE = Path.cwd()\nSS = WORKSPACE / 'screenshots'\nSS.mkdir(exist_ok=True)\n\nasync def create_session():\n    async with httpx.AsyncClient(timeout=60) as client:\n        r = await client.post(\n            'https://api.browserbase.com/v1/sessions',\n            headers={\n                'x-bb-api-key': os.environ['BROWSERBASE_API_KEY'],\n                'Content-Type': 'application/json',\n            },\n            json={\n                'projectId': os.environ['BROWSERBASE_PROJECT_ID'],\n                'proxies': True,\n                'browserSettings': {'advancedStealth': True},\n                'timeout': 900,\n            },\n        )\n        r.raise_for_status()\n        return r.json()\n\nasync def main():\n    session = await create_session()\n    print('SESSION', session['id'])\n    async with async_playwright() as pw:\n        browser = await pw.chromium.connect_over_cdp(session['connectUrl'])\n        context = browser.contexts[0] if browser.contexts else await browser.new_context()\n        page = context.pages[0] if context.pages else await context.new_page()\n        await page.set_viewport_size({'width': 1280, 'height': 1800})\n\n        # Etsy\n        await page.goto('https://www.etsy.com/c/home-and-living/home-decor/ornaments-and-accents/ornaments/christmas-ornaments', wait_until='domcontentloaded')\n        await page.wait_for_timeout(5000)\n        await page.screenshot(path=str(SS/'explore_etsy_area.png'))\n        print('ETSY URL', page.url)\n        print('ETSY TITLE', await page.title())\n        links = await page.locator('a').evaluate_all(\"els => els.map(a => ({text:(a.innerText||'').trim(), href:a.href})).filter(x => /personal|family|name|ornament/i.test(x.text)).slice(0,20)\")\n        print('ETSY CANDIDATE LINKS', links)\n        if links:\n            await page.goto(links[0]['href'], wait_until='domcontentloaded')\n            await page.wait_for_timeout(5000)\n            await page.screenshot(path=str(SS/'explore_etsy_listing.png'))\n            print('ETSY LISTING URL', page.url)\n            print('ETSY LISTING TITLE', await page.title())\n            txt = await page.locator('body').inner_text()\n            print('ETSY TEXT SNIP', re.sub(r'\\s+', ' ', txt)[:1500])\n\n        # Amazon\n        page2 = await context.new_page()\n        await page2.set_viewport_size({'width': 1280, 'height': 1800})\n        await page2.goto('https://www.amazon.com/s?k=marble+cheese+board', wait_until='domcontentloaded')\n        await page2.wait_for_timeout(5000)\n        await page2.screenshot(path=str(SS/'explore_amazon_results.png'))\n        print('AMZN URL', page2.url)\n        print('AMZN TITLE', await page2.title())\n        links2 = await page2.locator('a').evaluate_all(\"els => els.map(a => ({text:(a.innerText||'').trim(), href:a.href})).filter(x => /marble/i.test(x.text) && /board|serving|cheese/i.test(x.text)).slice(0,15)\")\n        print('AMZN CANDIDATE LINKS', links2[:8])\n        if links2:\n            href = links2[0]['href']\n            await page2.goto(href, wait_until='domcontentloaded')\n            await page2.wait_for_timeout(5000)\n            await page2.screenshot(path=str(SS/'explore_amazon_product.png'))\n            print('AMZN PRODUCT URL', page2.url)\n            print('AMZN PRODUCT TITLE', await page2.title())\n            body = await page2.locator('body').inner_text()\n            print('AMZN TEXT SNIP', re.sub(r'\\s+', ' ', body)[:1500])\n\n        # USPS\n        page3 = await context.new_page()\n        await page3.set_viewport_size({'width': 1280, 'height': 1800})\n        await page3.goto('https://store.usps.com/store/results/stamps/_/N-9y93lv', wait_until='domcontentloaded')\n        await page3.wait_for_timeout(5000)\n        await page3.screenshot(path=str(SS/'explore_usps_results.png'))\n        print('USPS URL', page3.url)\n        print('USPS TITLE', await page3.title())\n        links3 = await page3.locator('a').evaluate_all(\"els => els.map(a => ({text:(a.innerText||'').trim(), href:a.href})).filter(x => /forever/i.test(x.text)).slice(0,20)\")\n        print('USPS CANDIDATE LINKS', links3[:10])\n        if links3:\n            await page3.goto(links3[0]['href'], wait_until='domcontentloaded')\n            await page3.wait_for_timeout(5000)\n            await page3.screenshot(path=str(SS/'explore_usps_product.png'))\n            print('USPS PRODUCT URL', page3.url)\n            print('USPS PRODUCT TITLE', await page3.title())\n            body = await page3.locator('body').inner_text()\n            print('USPS TEXT SNIP', re.sub(r'\\s+', ' ', body)[:1200])\n        await browser.close()\n\nasyncio.run(main())\nPY",
