        "bash_command": "cd RELEASE_WORKSPACE && python - <<'PY'\nimport asyncio, os, httpx, re\nfrom pathlib import Path\nfrom playwright.async_api import async_playwright\n\nWORKSPACE = Path.cwd()\nSS = WORKSPACE / 'screenshots'\nSS.mkdir(exist_ok=True)\n\nasync def create_session():\n    async with httpx.AsyncClient(timeout=60) as client:\n        r = await client.post(\n            'https://api.browserbase.com/v1/sessions',\n            headers={'x-bb-api-key': os.environ['BROWSERBASE_API_KEY'], 'Content-Type': 'application/json'},\n            json={'projectId': os.environ['BROWSERBASE_PROJECT_ID'], 'proxies': True, 'browserSettings': {'advancedStealth': True}, 'timeout': 900},\n        )\n        r.raise_for_status()\n        return r.json()\n\nasync def main():\n    session = await create_session()\n    print('SESSION', session['id'])\n    async with async_playwright() as pw:\n        browser = await pw.chromium.connect_over_cdp(session['connectUrl'])\n        context = browser.contexts[0] if browser.contexts else await browser.new_context()\n        page = context.pages[0] if context.pages else await context.new_page()\n        await page.set_viewport_size({'width': 1280, 'height': 1800})\n        await page.goto('https://www.google.com/search?q=site%3Aetsy.com+personalized+family+christmas+ornament+etsy', wait_until='domcontentloaded')\n        await page.wait_for_timeout(5000)\n        await page.screenshot(path=str(SS/'explore4_google_etsy.png'))\n        links = await page.locator('a').evaluate_all(\"els => els.map(a => ({text:(a.innerText||a.getAttribute('aria-label')||'').replace(/\\\\s+/g,' ').trim(), href:a.href})).filter(x => /etsy\\.com\\/listing\\//i.test(x.href)).slice(0,10)\")\n        print('GOOGLE ETSY LINKS', links)\n        target = links[0]['href'] if links else None\n        if target and target.startswith('/url?q='):\n            target = target.split('/url?q=',1)[1].split('&',1)[0]\n        if target:\n            print('TARGET', target)\n            await page.goto(target, wait_until='domcontentloaded')\n            await page.wait_for_timeout(7000)\n            await page.screenshot(path=str(SS/'explore4_etsy_listing.png'))\n            print('ETSY URL', page.url)\n            print('ETSY TITLE', await page.title())\n            for sel in ['h1', '[data-selector=\"listing-page-title\"]', '[data-selector=\"price-only\"]', '[data-buy-box-region=\"price\"]', 'select', 'input', 'textarea']:\n                try:\n                    count = await page.locator(sel).count()\n                    print('COUNT', sel, count)\n                    if count:\n                        texts = []\n                        for i in range(min(count,5)):\n                            try:\n                                texts.append((await page.locator(sel).nth(i).inner_text(timeout=1500)).strip())\n                            except:\n                                try:\n                                    texts.append(await page.locator(sel).nth(i).get_attribute('aria-label'))\n                                except:\n                                    texts.append('')\n                        print('TEXTS', sel, texts)\n                except Exception as e:\n                    print('SELFAIL', sel, type(e).__name__)\n            body = re.sub(r'\\s+', ' ', await page.locator('body').inner_text())\n            print('BODY', body[:3000])\n        await browser.close()\n\nasyncio.run(main())\nPY",
